#include <bits/stdc++.h>
using namespace std;

int dis[205][205];

int main()
{
	int n, m, ans = 2e9;
	cin >> n >> m;
	memset(dis, 0x3f, sizeof dis);
	for(int i = 1; i <= m; i++)
	{
		int u, v, w;
		cin >> u >> v >> w;
		dis[u][v] = min(w, dis[u][v]);
		dis[v][u] = min(w, dis[u][v]);
	}
	for(int i = 1; i <= n; i++)
		dis[i][i] = 0;
	for(int k = 1; k <= n; k++)
		for(int i = 1; i <= n; i++)
			for(int j = 1; j <= n; j++)
				dis[i][j] = min(dis[i][j], dis[i][k] + dis[k][j]);
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= n; j++)
		{
			int sum = 0;
			for(int u = 1; u < n; u++)
				for(int v = u + 1; v <= n; v++)
				{
					int s1 = dis[u][v];
					int s2 = dis[u][i] + dis[j][v];
					int s3 = dis[u][j] + dis[i][v];
					sum += min({s1, s2, s3});
				}
			ans = min(ans, sum);
		}
	cout << ans << endl;
}
